        goto fail;
    }

    /* Success: Caller is responsible for freeing ctx->temp_buffer */
    return 0;

fail:
    /* 
     * --- Stage 4: Resource Management and Error Handling --- 
     * Centralized cleanup to prevent double-free vulnerabilities.
     * By setting the pointer to NULL after free, we ensure that any subsequent
     * calls to free() on this context will be safe no-ops.
     */
    if (ctx->temp_buffer != NULL) {
        free(ctx->temp_buffer);
        ctx->temp_buffer = NULL;
    }
    ctx->buffer_size = 0;
    return -1;
}
